<?php require_once __DIR__.'/includes/functions.php'; require_login(); $page_title='Kết quả bài làm';
if(current_user()['role']==='student'){$st=db()->prepare('SELECT a.*,e.code,e.title,s.name subject_name,u.name student FROM attempts a JOIN exams e ON e.id=a.exam_id JOIN subjects s ON s.id=e.subject_id JOIN users u ON u.id=a.user_id WHERE a.user_id=? ORDER BY a.started_at DESC');$st->execute([current_user()['id']]);}else{$st=db()->prepare('SELECT a.*,e.code,e.title,s.name subject_name,u.name student FROM attempts a JOIN exams e ON e.id=a.exam_id JOIN subjects s ON s.id=e.subject_id JOIN users u ON u.id=a.user_id ORDER BY a.started_at DESC');$st->execute();}$rows=$st->fetchAll(); include __DIR__.'/includes/header.php'; ?>
<div class="card"><h2>Kết quả</h2><table class="table"><tr><th>Học sinh</th><th>Đề</th><th>Môn</th><th>Điểm</th><th>Trạng thái</th><th>Thời gian</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['student']) ?></td><td><?= e($r['code'].' - '.$r['title']) ?></td><td><?= e($r['subject_name']) ?></td><td><strong><?= e($r['score']) ?>/<?= e($r['max_score']) ?></strong></td><td><?= e($r['status']) ?></td><td><?= e($r['started_at']) ?><br><?= e($r['submitted_at']) ?></td></tr><?php endforeach; ?></table></div>
<?php include __DIR__.'/includes/footer.php'; ?>
